import {
  Table,
  TableCaption,
  TableHeader,
  TableRow,
  TableHead,
  TableBody,
  TableCell
} from '@/components/ui/table';
import { Experience } from '@/types/Experience';
import dateFormater from '@/utils/dateFormater';
import useFetchData from '@/hooks/useFetchData';
import EditExperienceModal from '../EditExperienceModal';

// TODO: refatorar o fetch das experiências e o componente

export default async function ExperiencesTable() {
  const { experiences } = await useFetchData();
  const { data, lastExperience } = experiences;

  console.log(data);

  return (
    <>
      <Table className="w-full pb-10 text-gray lg:justify-self-center lg:text-lg 2xl:w-8/10 dark:text-white">
        <TableCaption className="pb-5 text-start text-xl">
          Lista de experiências
        </TableCaption>
        <TableHeader>
          <TableRow className="*:text-center lg:*:text-start">
            <TableHead className="w-[50px]">Nome</TableHead>
            <TableHead>Descrição</TableHead>
            <TableHead>Início</TableHead>
            <TableHead>Fim</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          <TableRow>
            <TableCell className="w-[100px] lg:w-[200px]">
              <h3 className="text-sm font-semibold text-wrap text-gray lg:text-lg dark:text-white">
                {lastExperience?.title}
              </h3>
            </TableCell>
            <TableCell className="max-w-[100px]">
              <p className="text-small text-wrap">
                {lastExperience?.description}
              </p>
            </TableCell>
            <TableCell className="max-w-[100px]">
              <p className="text-wrap">
                {dateFormater(lastExperience.startedAt)}
              </p>
            </TableCell>
            <TableCell className="max-w-[100px]">
              <p className="text-wrap">Presente</p>
            </TableCell>
            <TableCell className="w-[50px]">
              <EditExperienceModal identifier={lastExperience.id} />
            </TableCell>
          </TableRow>
          {experiences &&
            data.map((experience: Experience) => (
              <TableRow
                key={experience.id}
                className="*:text-center lg:*:text-start"
              >
                <TableCell className="w-[100px] lg:w-[200px]">
                  <h3 className="text-sm font-semibold text-wrap text-gray lg:text-lg dark:text-white">
                    {experience.title}
                  </h3>
                </TableCell>
                <TableCell className="max-w-[100px]">
                  <p className="text-small text-wrap">
                    {experience.description}
                  </p>
                </TableCell>
                <TableCell className="max-w-[100px]">
                  <p className="text-wrap">
                    {dateFormater(experience.startedAt)}
                  </p>
                </TableCell>
                <TableCell className="max-w-[100px]">
                  <p className="text-wrap">
                    {dateFormater(experience.finishedAt)}
                  </p>
                </TableCell>
                <TableCell className="w-[50px]">
                  {/* TODO: criar EditExperienceModal e action de edição de experiências*/}
                  <EditExperienceModal identifier={experience.id} />
                </TableCell>
              </TableRow>
            ))}
        </TableBody>
      </Table>
    </>
  );
}
